我的 Aseprite 小作品合集 ✨

.aseprite-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 18px;
  margin-top: 14px;
}

.aseprite-card {
  background: linear-gradient(180deg, #ffffff 0%, #f8fbff 100%);
  border: 1px solid #dbe8ff;
  border-radius: 14px;
  overflow: hidden;
  box-shadow: 0 10px 24px rgba(37, 99, 235, 0.12);
  transition: transform 180ms ease, box-shadow 180ms ease;
}

.aseprite-card:hover {
  transform: translateY(-3px);
  box-shadow: 0 14px 28px rgba(37, 99, 235, 0.18);
}

.aseprite-media {
  display: block;
  background: radial-gradient(circle at center, #7dd3fc 0%, #38bdf8 100%);
  padding: 14px;
}

.aseprite-media img {
  width: 100%;
  aspect-ratio: 1 / 1;
  object-fit: contain;
  image-rendering: pixelated;
  border-radius: 10px;
  background: rgba(255,255,255,0.5);
}

.aseprite-body {
  padding: 12px 14px 14px;
}

.aseprite-title {
  margin: 0;
  font-size: 16px;
  font-weight: 700;
  color: #0f172a;
}

.aseprite-meta {
  margin: 6px 0 0;
  font-size: 13px;
  color: #64748b;
}







